//HEX DISPLAY
static const uint8_t HEX_CODES[16] = {
    0x3F,0x06,0x5B,0x4F, // 0-3
    0x66,0x6D,0x7D,0x07, // 4-7
    0x7F,0x67,0x77,0x7C, // 8-9,A,b
    0x39,0x5E,0x79,0x71  // C,d,E,F
};

static void hex_write_digit(int n, int digit) {
    // n = display number 0-5 (0 = rightmost)
    uint8_t code = (digit >= 0 && digit <= 15) ? HEX_CODES[digit] : 0x00;
    if (n <= 3) {
        volatile int *reg = (volatile int *)HEX_BASE1;
        int shift = n * 8;
        int val = *reg;
        val &= ~(0xFF << shift);
        val |=  (code  << shift);
        *reg = val;
    } else {
        volatile int *reg = (volatile int *)HEX_BASE2;
        int shift = (n - 4) * 8;
        int val = *reg;
        val &= ~(0xFF << shift);
        val |=  (code  << shift);
        *reg = val;
    }
}

static void hex_blank(int n) {
    if (n <= 3) {
        volatile int *reg = (volatile int *)HEX_BASE1;
        int shift = n * 8;
        *reg = (*reg) & ~(0xFF << shift);
    } else {
        volatile int *reg = (volatile int *)HEX_BASE2;
        int shift = (n - 4) * 8;
        *reg = (*reg) & ~(0xFF << shift);
    }
}

// Show a 1 or 2 digit number on HEX1 (tens) and HEX0 (units)
static void hex_show_count(int n) {
    if (n < 0)  n = 0;
    if (n > 99) n = 99;
    hex_write_digit(0, n % 10);
    if (n >= 10) hex_write_digit(1, n / 10);
    else         hex_blank(1);
}

// Blank the counter displays
static void hex_blank_counter(void) {
    hex_blank(0);
    hex_blank(1);
}

// Show a single big digit on HEX0 (for 3-2-1 countdown)
static void hex_show_single(int d) {
    hex_blank(1);
    hex_write_digit(0, d);
}

static void hex_blank_all(void) {
    volatile int *r1 = (volatile int *)HEX_BASE1;
    volatile int *r2 = (volatile int *)HEX_BASE2;
    *r1 = 0;
    *r2 = 0;
}

//  PIXEL / DRAWING
static void plot_pixel(int x, int y, short int color) {
    volatile short int *addr =
        (volatile short int *)(pixel_buffer_start + (y << 10) + (x << 1));
    *addr = color;
}

static void draw_rect(int x, int y, int w, int h, short int color) {
    for (int r = y; r < y + h; r++)
        for (int c = x; c < x + w; c++)
            plot_pixel(c, r, color);
}

static void clear_screen(void) {
    draw_rect(0, 0, 320, 240, 0x0000);
}

