static void draw_letter(const uint8_t bmp[7][5], int x, int y, short int color) {
    for (int r = 0; r < 7; r++)
        for (int c = 0; c < 5; c++)
            if (bmp[r][c])
                draw_rect(x + c*SCALE, y + r*SCALE, SCALE, SCALE, color);
}

static void draw_bitmap_char(const uint8_t bmp[7], int x, int y, short int color) {
    for (int r = 0; r < 7; r++)
        for (int c = 0; c < 5; c++)
            if (bmp[r] & (1 << (4-c)))
                draw_rect(x + c*SCALE, y + r*SCALE, SCALE, SCALE, color);
}

// Draw a string — supports A-Z, a-z (auto-uppercased), 0-9, and : [ ] ? ! . - /
static void draw_string(const char *str, int x, int y, short int color) {
    int lw = 5*SCALE + GAP;
    for (int i = 0; str[i] != '\0'; i++) {
        char ch = str[i];
        int cx = x + i*lw;
        if      (ch >= 'A' && ch <= 'Z') draw_letter(font_table[ch-'A'], cx, y, color);
        else if (ch >= 'a' && ch <= 'z') draw_letter(font_table[ch-'a'], cx, y, color);
        else if (ch=='0') draw_bitmap_char(font_0,        cx,y,color);
        else if (ch=='1') draw_bitmap_char(font_1,        cx,y,color);
        else if (ch=='2') draw_bitmap_char(font_2,        cx,y,color);
        else if (ch=='3') draw_bitmap_char(font_3,        cx,y,color);
        else if (ch=='4') draw_bitmap_char(font_4,        cx,y,color);
        else if (ch=='5') draw_bitmap_char(font_5,        cx,y,color);
        else if (ch=='6') draw_bitmap_char(font_6,        cx,y,color);
        else if (ch=='7') draw_bitmap_char(font_7,        cx,y,color);
        else if (ch=='8') draw_bitmap_char(font_8,        cx,y,color);
        else if (ch=='9') draw_bitmap_char(font_9,        cx,y,color);
        else if (ch==':') draw_bitmap_char(font_colon,    cx,y,color);
        else if (ch=='[') draw_bitmap_char(font_lbracket, cx,y,color);
        else if (ch==']') draw_bitmap_char(font_rbracket, cx,y,color);
        else if (ch=='?') draw_bitmap_char(font_question, cx,y,color);
        else if (ch=='!') draw_bitmap_char(font_exclaim,  cx,y,color);
        else if (ch=='.') draw_bitmap_char(font_period,   cx,y,color);
        else if (ch=='-') draw_bitmap_char(font_dash,     cx,y,color);
        else if (ch=='/') draw_bitmap_char(font_slash,    cx,y,color);
        // space = blank, skip
    }
}

//  TEXT HELPERS
static void to_upper(char *dst, const char *src, int max) {
    int i;
    for (i = 0; i < max-1 && src[i]; i++) {
        char c = src[i];
        dst[i] = (c>='a' && c<='z') ? c-32 : c;
    }
    dst[i] = '\0';
}

// Draw a string centred horizontally at y
static void draw_centered(const char *s, int y, short int color) {
    int lw = 5*SCALE + GAP;
    int w  = (int)strlen(s) * lw;
    int x  = (320 - w) / 2;
    if (x < 0) x = 0;
    draw_string(s, x, y, color);
}

// Word-wrap draw: draw src centred, max_w pixels wide, starting at y.
// Returns y after last line drawn.
static int draw_wrapped(const char *src, int y, int max_w, short int color) {
    char buf[256];
    to_upper(buf, src, 256);

    char words[32][32];
    int wcount = 0;
    int bi = 0, wi = 0;
    while (buf[bi] && wcount < 32) {
        char c = buf[bi++];
        if (c == ' ') {
            if (wi > 0) { words[wcount][wi]='\0'; wcount++; wi=0; }
        } else {
            words[wcount][wi++] = c;
        }
    }
    if (wi > 0) { words[wcount][wi]='\0'; wcount++; }

    int lw     = 5*SCALE + GAP;
    int line_h = 7*SCALE + 3;
    int ls = 0;

    while (ls < wcount) {
        int le = ls, line_px = 0;
        while (le < wcount) {
            int wp  = (int)strlen(words[le]) * lw;
            int gap = (le > ls) ? lw : 0;
            if (line_px + gap + wp > max_w) break;
            line_px += gap + wp;
            le++;
        }
        if (le == ls) le++;  // force at least one word

        int x = (320 - line_px) / 2;
        if (x < 0) x = 0;
        for (int w = ls; w < le; w++) {
            draw_string(words[w], x, y, color);
            x += (int)strlen(words[w]) * lw + lw;
        }
        y += line_h;
        ls = le;
    }
    return y;
}

//  KEY POLLING  (level-based edge detect, no edgecap register)
static int prev_keys = 0;

// Returns bitmask of newly pressed keys this call (rising edge)
// Bit 0 = KEY0, Bit 1 = KEY1, Bit 2 = KEY2, Bit 3 = KEY3
static int keys_pressed(void) {
    volatile int *kp = (volatile int *)KEY_BASE;
    int cur  = (*kp) & 0xF;
    int edge = cur & ~prev_keys;
    prev_keys = cur;
    return edge;
}

// HARDWARE TIMER DELAY
#define TIMER_BASE     0xFF202000
#define TICKS_PER_SEC  100000000

static void delay_ticks(int ticks) {
    volatile int *timer = (volatile int *)TIMER_BASE;
    timer[1] = 0x8;
    timer[0] = 0;
    timer[2] = ticks & 0xFFFF;
    timer[3] = (ticks >> 16) & 0xFFFF;
    timer[1] = 0x4;
    while ((timer[0] & 0x1) == 0);
    timer[0] = 0;
}

static void delay_sec(int seconds) {
    for (int i = 0; i < seconds; i++)
        delay_ticks(TICKS_PER_SEC);
}

static void delay_ms(int ms) {
    delay_ticks((TICKS_PER_SEC / 1000) * ms);
}
// BACKGROUND IMAGE DRAW
static void draw_akinator_bg(void) {
    int n = (int)(sizeof(akinator_map) / sizeof(akinator_map[0]));
    if (n >= 320*240) {
        for (int i = 0; i < 320*240; i++)
            plot_pixel(i % 320, i / 320, (short int)akinator_map[i]);
    } else {
        for (int y = 0; y < 120 && y*160+159 < n; y++)
            for (int x = 0; x < 160; x++) {
                short int c = (short int)akinator_map[y*160 + x];
                plot_pixel(x*2,   y*2,   c);
                plot_pixel(x*2+1, y*2,   c);
                plot_pixel(x*2,   y*2+1, c);
                plot_pixel(x*2+1, y*2+1, c);
            }
    }
}

static void draw_screen2_bg(void) {
    int n = (int)(sizeof(background) / sizeof(background[0]));
    if (n >= 320*240) {
        for (int i = 0; i < 320*240; i++)
            plot_pixel(i % 320, i / 320, (short int)background[i]);
    } else if (n > 1) {
        for (int y = 0; y < 120 && y*160+159 < n; y++)
            for (int x = 0; x < 160; x++) {
                short int c = (short int)background[y*160 + x];
                plot_pixel(x*2,   y*2,   c);
                plot_pixel(x*2+1, y*2,   c);
                plot_pixel(x*2,   y*2+1, c);
                plot_pixel(x*2+1, y*2+1, c);
            }
    } else {
        // No background data — just use solid dark colour
        clear_screen();
    }
}

//  BAYES ENGINE
static float probabilities[NUM_FOODS];
static int   asked[NUM_QUESTIONS];
static int   pool_unlocked[NUM_POOLS];
int          any_pool_unlocked = 0;

static float fast_log2(float x) {
    if (x <= 0.0f) return -100.0f;
    int exp = 0;
    while (x < 1.0f)  { x *= 2.0f; exp--; }
    while (x >= 2.0f) { x *= 0.5f; exp++; }
    float y = x - 1.0f;
    float r = y * (1.4426950f - y * (0.7213475f - y * 0.4808983f));
    return r + (float)exp;
}

static void bayes_init(void) {
    float eq = 1.0f / NUM_FOODS;
    for (int i = 0; i < NUM_FOODS;     i++) probabilities[i]  = eq;
    for (int i = 0; i < NUM_QUESTIONS; i++) asked[i]          = 0;
    for (int i = 0; i < NUM_POOLS;     i++) pool_unlocked[i]  = 0;
    any_pool_unlocked = 0;
}

// answer: 0=YES  1=NO  2=SOMETIMES
static void bayes_update(int q, int answer) {
    float sum = 0.0f;
    for (int i = 0; i < NUM_FOODS; i++) {
        float w;
        if      (answer == 0) w = properties[i][q];
        else if (answer == 1) w = 1.0f - properties[i][q];
        else                  w = 0.5f;
        if (w < 0.001f) w = 0.001f;
        probabilities[i] *= w;
        sum += probabilities[i];
    }
    if (sum > 0.0f)
        for (int i = 0; i < NUM_FOODS; i++) probabilities[i] /= sum;

    for (int p = 0; p < NUM_POOLS; p++) {
        if (q == pool_defs[p][2] && answer == pool_defs[p][3]) {
            pool_unlocked[p] = 1;
            any_pool_unlocked = 1;
        }
    }
}

static float bayes_top_prob(void) {
    float best = 0.0f;
    for (int i = 0; i < NUM_FOODS; i++)
        if (probabilities[i] > best) best = probabilities[i];
    return best;
}

static int bayes_top_candidate(void) {
    int best = 0;
    for (int i = 1; i < NUM_FOODS; i++)
        if (probabilities[i] > probabilities[best]) best = i;
    return best;
}

static int bayes_next_question(void) {
    int  best_q  = -1;
    float best_ig = -1.0f;

    // --- Phase 1: ask all pool-unlock questions first ---
    int all_p1_asked = 1;
    for (int i = 0; i < P1_END; i++) {
        if (!asked[i]) { all_p1_asked = 0; break; }
    }
    // Skip phase 1 early if a specific pool got unlocked
    if (pool_unlocked[1] || pool_unlocked[2]) all_p1_asked = 1;

    if (!all_p1_asked) {
        float H = 0.0f;
        for (int i = 0; i < NUM_FOODS; i++)
            if (probabilities[i] > 1e-9f)
                H -= probabilities[i] * fast_log2(probabilities[i]);

        for (int q = 0; q < P1_END; q++) {
            if (asked[q]) continue;
            float p_yes = 0.0f;
            for (int i = 0; i < NUM_FOODS; i++)
                p_yes += probabilities[i] * properties[i][q];
            float p_no = 1.0f - p_yes;
            float H_yes = 0.0f, H_no = 0.0f;
            if (p_yes > 1e-6f)
                for (int i = 0; i < NUM_FOODS; i++) {
                    float post = (probabilities[i]*properties[i][q]) / p_yes;
                    if (post > 1e-9f) H_yes -= post * fast_log2(post);
                }
            if (p_no > 1e-6f)
                for (int i = 0; i < NUM_FOODS; i++) {
                    float post = (probabilities[i]*(1.0f-properties[i][q])) / p_no;
                    if (post > 1e-9f) H_no -= post * fast_log2(post);
                }
            float ig = H - (p_yes*H_yes + p_no*H_no);
            if (ig > best_ig) { best_ig = ig; best_q = q; }
        }
        if (best_q >= 0) { asked[best_q] = 1; return best_q; }
    }

    // --- Phase 2: pick best question from unlocked pools ---
    float H = 0.0f;
    for (int i = 0; i < NUM_FOODS; i++)
        if (probabilities[i] > 1e-9f)
            H -= probabilities[i] * fast_log2(probabilities[i]);

    // Find top-3 candidates for focused mode
    int   top3[3]      = {-1,-1,-1};
    float top3p[3]     = { 0, 0, 0};
    for (int i = 0; i < NUM_FOODS; i++) {
        if      (probabilities[i] > top3p[0]) { top3[2]=top3[1]; top3p[2]=top3p[1]; top3[1]=top3[0]; top3p[1]=top3p[0]; top3[0]=i; top3p[0]=probabilities[i]; }
        else if (probabilities[i] > top3p[1]) { top3[2]=top3[1]; top3p[2]=top3p[1]; top3[1]=i; top3p[1]=probabilities[i]; }
        else if (probabilities[i] > top3p[2]) { top3[2]=i; top3p[2]=probabilities[i]; }
    }
    int focused = (top3p[1] > 0.25f && top3p[0] < 0.75f && (top3p[0]-top3p[1]) < 0.15f);
    int fcount  = (top3p[2] < 0.05f) ? 2 : 3;

    // Best pool
    int   best_pool = -1;
    float max_psum  = -1.0f;
    for (int p = 0; p < NUM_POOLS; p++) {
        if (!pool_unlocked[p]) continue;
        float s = 0.0f;
        for (int i = 0; i < NUM_FOODS; i++)
            if (properties[i][pool_defs[p][2]] > 0.8f) s += probabilities[i];
        if (s > max_psum) { max_psum = s; best_pool = p; }
    }
    if (pool_unlocked[4]) best_pool = 4;
    if (pool_unlocked[0]) best_pool = 0;

    best_ig = -1.0f;
    best_q  = -1;
    for (int q = 0; q < NUM_QUESTIONS; q++) {
        if (asked[q]) continue;

        // Pool stickiness
        int q_pool = -1;
        for (int p = 0; p < NUM_POOLS; p++)
            if (q >= pool_defs[p][0] && q < pool_defs[p][1]) { q_pool = p; break; }

        if (best_pool != -1 && q_pool != best_pool) {
            int left = 0;
            for (int k = pool_defs[best_pool][0]; k < pool_defs[best_pool][1]; k++)
                if (!asked[k]) left++;
            if (left > 0) continue;
        }

        int unlocked = 0;
        for (int p = 0; p < NUM_POOLS; p++)
            if (q >= pool_defs[p][0] && q < pool_defs[p][1] && pool_unlocked[p])
                { unlocked = 1; break; }
        if (!unlocked) continue;

        float p_yes = 0.0f, tw = 0.0f;
        if (focused) {
            for (int t = 0; t < fcount; t++) {
                if (top3[t] < 0) continue;
                p_yes += probabilities[top3[t]] * properties[top3[t]][q];
                tw    += probabilities[top3[t]];
            }
        } else {
            for (int i = 0; i < NUM_FOODS; i++) if (probabilities[i] > 0.001f) {
                p_yes += probabilities[i] * properties[i][q];
                tw    += probabilities[i];
            }
        }
        if (tw > 0) p_yes /= tw;
        float p_no = 1.0f - p_yes;

        float H_yes = 0.0f, H_no = 0.0f;
        if (p_yes > 1e-6f) {
            if (focused) for (int t = 0; t < fcount; t++) { if (top3[t]<0) continue; float post=(probabilities[top3[t]]*properties[top3[t]][q])/p_yes; if(post>1e-9f) H_yes-=post*fast_log2(post); }
            else         for (int i = 0; i < NUM_FOODS; i++) { float post=(probabilities[i]*properties[i][q])/p_yes; if(post>1e-9f) H_yes-=post*fast_log2(post); }
        }
        if (p_no > 1e-6f) {
            if (focused) for (int t = 0; t < fcount; t++) { if (top3[t]<0) continue; float post=(probabilities[top3[t]]*(1.0f-properties[top3[t]][q]))/p_no; if(post>1e-9f) H_no-=post*fast_log2(post); }
            else         for (int i = 0; i < NUM_FOODS; i++) { float post=(probabilities[i]*(1.0f-properties[i][q]))/p_no; if(post>1e-9f) H_no-=post*fast_log2(post); }
        }

        float ig = H - (p_yes*H_yes + p_no*H_no);
        if (focused && top3[0]>=0 && top3[1]>=0) {
            float sep = properties[top3[0]][q] - properties[top3[1]][q];
            if (sep < 0) sep = -sep;
            ig += sep * 0.8f;
        }
        if (ig > best_ig) { best_ig = ig; best_q = q; }
    }
    if (best_q >= 0) asked[best_q] = 1;
    return best_q;
}

//  SCREEN DRAW FUNCTIONS
// Screen 1: akinator image + flavour text
static void draw_screen1(void) {
    SCALE = 1;
    clear_screen();
    draw_akinator_bg();
    draw_string("THINK ABOUT A",   104, 50, 0xFFFF);
	draw_string("FOOD I WILL TRY", 100, 65, 0xFFFF);
	draw_string("TO GUESS IT",     108, 80, 0xFFFF);
}

// Screen 2: background + press any key text
static void draw_screen2(void) {
    SCALE = 2;
    clear_screen();
    draw_screen2_bg();
    draw_centered("PRESS ANY",    90, 0xFFFF);
    draw_centered("KEY[3:0]",    110, 0xFFFF);
    draw_centered("TO START",    130, 0xFFFF);
}

// Countdown: shows 3 2 1 on VGA and HEX0, with ~1s delay each
static void draw_countdown(void) {
    SCALE = 4;
    draw_screen2_bg();
    for (int d = 3; d >= 1; d--) {
         draw_screen2_bg();
        char buf[2] = { '0' + d, '\0' };
        draw_centered(buf, 100, 0xFFFF);
        hex_show_single(d);
        delay_sec(1);   
    }
    hex_blank_all();
    SCALE = 1;
}

// Draw current question text (word-wrapped, centred)
// Also draws the KEY hint line at bottom
static void draw_question_screen(int q_idx, int questions_left) {
     draw_screen2_bg();
	SCALE = 2;

    // Question text — centred, word-wrapped, white
    int y_end = draw_wrapped(questions[q_idx], 100, 300, 0xFFFF);
    (void)y_end;

    // KEY hints at bottom — fixed positions
    // KEY0=NO  KEY1=SOMETIMES  KEY2=YES
    SCALE = 1;
    draw_string("YES",        30,  150, 0x07E0 );  // green
    draw_string("SOMETIMES", 125, 150, 0xFFE0);  // yellow
    draw_string("NO",       270, 150, 0xF800);  // red

    // Update HEX counter
    hex_show_count(questions_left);
}

// Draw the final guess screen
static void draw_guess_screen(int candidate) {
    draw_screen2_bg();
    SCALE = 1;
    draw_centered("FINAL GUESS",  80, 0xFFFF);

    // Food name — word-wrapped centred
	SCALE = 2;
    draw_wrapped(food_names[candidate], 100, 300, 0xFFE0);  // yellow

	SCALE = 1;
    draw_centered("WAS I RIGHT?", 140, 0xFFFF);
    draw_string("YES", 100, 160, 0x07E0);
    draw_string("NO", 200, 160, 0xF800);

    hex_blank_counter();
}

// Draw win/lose end screen
static void draw_end_screen(int ai_won) {
    draw_screen2_bg();
    SCALE = 2;
    if (ai_won) {
        draw_centered("I WIN!",      90, 0x07E0);
    } else {
        draw_centered("YOU WIN!",    90, 0xF800);
    }
	
	SCALE = 1;
    draw_centered("PLAY AGAIN?", 140, 0xFFFF);
    draw_string("YES",   100, 160, 0x07E0);
    draw_string("NO", 200, 160, 0xF800);
}

//  MAIN
int main(void) {
    pixel_buffer_start = *pixel_ctrl_ptr;
    hex_blank_all();

    // -------------------------------------------------------
    //  GAME STATE MACHINE
    //  0 = screen1 (akinator image, press any key)
    //  1 = screen2 (press any key to start)
    //  2 = countdown (3-2-1)
    //  3 = asking questions
    //  4 = final guess
    //  5 = end screen (win/lose)
    // -------------------------------------------------------
    int state = 0;
    int current_q       = -1;
    int questions_left  = 20;   // max questions shown on HEX
    int questions_asked = 0;
    int final_candidate = 0;

    draw_screen1();

    while (1) {
        int kp = keys_pressed();   // bitmask of newly pressed keys
        int key0 = (kp & 0x1);    // KEY0 = NO
        int key1 = (kp & 0x2);    // KEY1 = SOMETIMES
        int key2 = (kp & 0x4);    // KEY2 = YES
        int any  = (kp != 0);

        switch (state) {

        // -------- Screen 1: akinator image --------
        case 0:
            if (any) {
                draw_screen2();
                state = 1;
            }
            break;

        // -------- Screen 2: press any key to start --------
        case 1:
            if (any) {
                // Countdown runs immediately, blocking
                draw_countdown();

                // Init game
                bayes_init();
                questions_left  = 20;
                questions_asked = 0;
                current_q = bayes_next_question();
                draw_question_screen(current_q, questions_left);
                state = 3;
            }
            break;

        // -------- State 2 unused (countdown is blocking) --------
        case 2:
            break;

        // -------- Asking questions --------
        case 3: {
            int answer = -1;
            if (key2) answer = 0;        // KEY2 = YES
            else if (key0) answer = 1;   // KEY0 = NO
            else if (key1) answer = 2;   // KEY1 = SOMETIMES

            if (answer >= 0) {
                bayes_update(current_q, answer);
                questions_asked++;
                questions_left = 20 - questions_asked;
                if (questions_left < 0) questions_left = 0;

                float top = bayes_top_prob();

                // Guess when confident enough OR out of questions
                if (top > 0.70f || questions_asked >= 20) {
                    final_candidate = bayes_top_candidate();
                    draw_guess_screen(final_candidate);
                    state = 4;
                } else {
                    current_q = bayes_next_question();
                    if (current_q < 0) {
                        // No more questions — guess anyway
                        final_candidate = bayes_top_candidate();
                        draw_guess_screen(final_candidate);
                        state = 4;
                    } else {
                        draw_question_screen(current_q, questions_left);
                    }
                }
            }
            break;
        }

        // -------- Final guess --------
        case 4:
            if (key2) {
                // YES — AI wins
                draw_end_screen(1);
                state = 5;
            } else if (key0) {
                // NO — player wins
                draw_end_screen(0);
                state = 5;
            }
            break;

        // -------- End screen --------
        case 5:
            if (key2) {
                SCALE = 1;
                draw_screen2();
                hex_blank_all();
                state = 0;
            } else if (key0) {
				hex_blank_all();
				draw_screen1();
				state = 0;
            }
            break;
        }
    }

    return 0;
}